export const adminDashboardDesign = {
  colors: {
    sidebar: "bg-gray-900 text-white",
    navbar: "bg-white border-b",
    overlay: "bg-black/40",
    hover: "hover:bg-gray-800",
    toggleBtn: "text-gray-700 hover:text-indigo-600 transition",
  },

  layout: {
    wrapper: "flex h-screen overflow-hidden bg-gray-100",

    sidebar:
      "w-64 flex-shrink-0 flex flex-col p-6 space-y-6",

    rightSide: "flex flex-col flex-1",

    navbar:
      "h-16 flex items-center justify-between px-4 sm:px-6 lg:px-8 bg-white border-b",

    content:
      "flex-1 overflow-y-auto p-4 sm:p-6 lg:p-8",

    navItem:
      "px-3 py-2 rounded-lg transition cursor-pointer text-sm font-medium",
  },
};
